public void serializeWithType(Object value, JsonGenerator gen, SerializerProvider provider, TypeSerializer typeSer) throws IOException { Object delegateValue = convertValue(value); if (_delegateSerializer == null) { provider.findValueSerializer(delegateValue.getClass(), null).serializeWithType(delegateValue, gen, provider, typeSer); } else { _delegateSerializer.serializeWithType(delegateValue, gen, provider, typeSer); } }